#!/usr/bin/env python3
# Partial-tolerant scaling-trend analysis. Same math as scaling-trend-analysis.py but
# (a) only uses g1-g4 groups that have >=2 members present in BOTH files (common texts),
# (b) prints per-file numbers + which groups/texts were used, so a partial 2.9B capture
# still yields honest within/across separation. Usage: script.py acts_A.json acts_B.json
#
# RESULT (2026-06-30, rwkv7 SSM resonance semantic-key scaling test, 4-group common subset,
# RAW final pre-lm_head hidden cosine — same metric across all sizes):
#   0.1B  D=768 : sep=+0.258  ordering-acc=98.3%  clean-margin=-0.169
#   0.4B  D=1024: sep=+0.258  ordering-acc=99.8%  clean-margin=-0.004
#   2.9B  D=2560: sep=+0.033  ordering-acc=98.6%  clean-margin=-0.006   [within=0.974 across=0.940]
# VERDICT: the "separation sharpens ~7x with size" scaling thesis is NOT supported at 2.9B.
#   The RAW-cosine gap COLLAPSES 8x (+0.258 -> +0.033) because the big-model final hidden is
#   anisotropy-dominated (all cosines crushed to ~0.94-0.97 by a common-mode "rogue" dim).
#   Ordering-acc does NOT keep climbing (98.3->99.8->98.6 = plateau/slight reversal).
#   Under MEAN-CENTERING (remove common-mode; see resonance-anisotropy-diag.py) the semantic
#   key SURVIVES at 2.9B (centered sep=+0.667, acc=100%, clean-margin=+0.010) but is still
#   SMALLER than 0.4B (+0.795) -> even anisotropy-corrected, separation shrinks, not sharpens.
#   => a whitened/centered resonance signature is a viable cache key at scale, but per-hit
#      margin does not grow with model size; raw signatures would collide (need per-model whiten).
import json, sys, numpy as np
from itertools import combinations
GROUPS=['g1_paris','g2_math','g3_sky','g4_freeze']
def load(f):
    d=json.load(open(f)); return d['records'], d['hidden_dim']
def cos(a,b): return float(a@b/(np.linalg.norm(a)*np.linalg.norm(b)))
def texts(recs,g): return set(x['text'] for x in recs if x['group']==g)
def analyze(name, recs, D, common, groups):
    s={g:[np.array(x['activation'],float) for x in recs if x['group']==g and x['text'] in common[g]] for g in groups}
    within=np.array([cos(a,b) for g in groups for a,b in combinations(s[g],2)])
    across=np.array([cos(s[gi][ai],s[gj][aj]) for i,gi in enumerate(groups) for gj in groups[i+1:] for ai in range(len(s[gi])) for aj in range(len(s[gj]))])
    acc=100*sum(w>a for w in within for a in across)/(len(within)*len(across))
    print(f"{name} D={D}: sep={within.mean()-across.mean():+.3f} ordering-acc={acc:.1f}% "
          f"clean-margin={within.min()-across.max():+.3f}  "
          f"[within_mean={within.mean():.3f} across_mean={across.mean():.3f} "
          f"n_within={len(within)} n_across={len(across)}]")
    return within.mean()-across.mean(), acc
rA,DA=load(sys.argv[1]); rB,DB=load(sys.argv[2])
common={g:texts(rA,g)&texts(rB,g) for g in GROUPS}
groups=[g for g in GROUPS if len(common[g])>=2]
print("groups used (>=2 common members):", groups)
for g in GROUPS:
    print(f"  {g}: {len(common[g])} common texts", "" if g in groups else "(SKIPPED <2)")
print()
analyze(sys.argv[1],rA,DA,common,groups); analyze(sys.argv[2],rB,DB,common,groups)
